-- 012_supplier_source_photos.sql
-- Generated by _inbox/generate_supplier_photos_migration.py
--
-- Adds a photo_url column to inventory_supplier_sources and populates
-- it for every OPS letter / number colour source — turning the Reorder
-- dropdown into a visual colour picker.
--
-- The inventory item's primary photo_url stays as-is (gold-letter image
-- on letter SKUs, black-number on number SKUs). The per-source photo is
-- additive — used in the dropdown only.

ALTER TABLE inventory_supplier_sources ADD COLUMN photo_url TEXT;

-- OPS letter colours — one UPDATE per colour, scoped to that supplier_name
-- pattern. Idempotent because re-applying a UPDATE with the same value is a
-- no-op.
UPDATE inventory_supplier_sources
   SET photo_url = 'https://onlinepartysupplies.com.au/cdn/shop/files/16-inch-gold-foil-alphabet-letter-a-z-shaped-foil-balloon-party-decorations_600x.webp', updated_at = datetime('now')
 WHERE supplier_name = 'OPS — Gold'
   AND inventory_item_id IN (SELECT id FROM inventory_items WHERE sku LIKE 'foil-topper-letter-%' AND sku != 'foil-topper-letter');
UPDATE inventory_supplier_sources
   SET photo_url = 'https://onlinepartysupplies.com.au/cdn/shop/files/16-inch-rose-gold-a-z-alphabet-letters-foil-balloons-party-decorations-1_600x.jpg', updated_at = datetime('now')
