-- Latex Stylex sources — copy the inventory item's photo_url onto the source
-- so the dropdown shows a thumbnail there too. (Inventory item already has
-- the right swatch from migration 010.)
UPDATE inventory_supplier_sources
   SET photo_url = (SELECT photo_url FROM inventory_items WHERE inventory_items.id = inventory_supplier_sources.inventory_item_id),
       updated_at = datetime('now')
 WHERE supplier_name = 'Stylex Balloons'
   AND photo_url IS NULL
   AND inventory_item_id IN (SELECT id FROM inventory_items WHERE sku LIKE 'balloon-latex-5in-stylex-%');